// Extract inputs passed from the toolWorkflow
const inp = $input.first().json;

if (!inp.deal_id) throw new Error('Missing required field: deal_id');
if (!inp.output_type) throw new Error('Missing required field: output_type');

return [{ json: {
  deal_id: inp.deal_id,
  output_type: inp.output_type,
  recipient_email: inp.recipient_email || null,
  recipient_name: inp.recipient_name || null,
  instructions: inp.instructions || ''
}}];

// Format the draft response for the chat agent
const result = $input.first().json;

if (result.status !== 'draft') {
  throw new Error('Unexpected response from output-request: ' + JSON.stringify(result));
}

// Return a formatted string that the chat agent can display to Austin
const formatted = `DRAFT READY\n` +
  `Draft ID: ${result.draft_id}\n` +
  `Output Type: ${result.output_type}\n` +
  `Deal: ${result.company_name} (${result.deal_id})\n` +
  `To: ${result.recipient_name || ''} <${result.recipient_email || ''}>\n` +
  `Model: ${result.model_used}\n\n` +
  `Subject: ${result.subject}\n\n` +
  `---\n${result.body}\n---\n\n` +
  `Summary: ${result.content_summary}`;

return [{ json: { output: formatted, draft_id: result.draft_id, subject: result.subject, body: result.body } }];
